// ============================================================
// HydraNet - Reports API Route
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'
import { generateTrackingId } from '@/lib/auth'
import type { ReportStatus, ReportPriority } from '@prisma/client'

// GET /api/reports - List all reports with filtering
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const utilityId = searchParams.get('utilityId')
    const dmaId = searchParams.get('dmaId')
    const status = searchParams.get('status') as ReportStatus | null
    const priority = searchParams.get('priority') as ReportPriority | null

    const reports = await prisma.report.findMany({
      where: {
        ...(utilityId && { utilityId }),
        ...(dmaId && { dmaId }),
        ...(status && { status }),
        ...(priority && { priority }),
      },
      include: {
        utility: { select: { id: true, name: true } },
        dma: { select: { id: true, name: true } },
        branch: { select: { id: true, name: true } },
        team: { select: { id: true, name: true } },
        assignedEngineer: { select: { id: true, name: true } },
      },
      orderBy: { createdAt: 'desc' },
    })

    const formattedReports = reports.map((report) => ({
      ...report,
      utilityName: report.utility.name,
      dmaName: report.dma.name,
      branchName: report.branch?.name || null,
      teamName: report.team?.name || null,
      assignedEngineerName: report.assignedEngineer?.name || null,
    }))

    return NextResponse.json(formattedReports)
  } catch (error) {
    console.error('Error fetching reports:', error)
    return NextResponse.json({ error: 'Failed to fetch reports' }, { status: 500 })
  }
}

// POST /api/reports - Create a new report
export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    const report = await prisma.report.create({
      data: {
        trackingId: generateTrackingId(),
        description: data.description,
        latitude: data.latitude,
        longitude: data.longitude,
        address: data.address || null,
        priority: (data.priority as ReportPriority) || 'medium',
        status: 'new',
        utilityId: data.utilityId,
        dmaId: data.dmaId,
        branchId: data.branchId || null,
        teamId: data.teamId || null,
        assignedEngineerId: data.assignedEngineerId || null,
        reporterName: data.reporterName,
        reporterPhone: data.reporterPhone,
        notes: data.notes || null,
        slaDeadline: new Date(Date.now() + (data.slaDays || 7) * 24 * 60 * 60 * 1000),
      },
      include: {
        utility: { select: { id: true, name: true } },
        dma: { select: { id: true, name: true } },
        branch: { select: { id: true, name: true } },
        team: { select: { id: true, name: true } },
        assignedEngineer: { select: { id: true, name: true } },
      },
    })

    const formattedReport = {
      ...report,
      utilityName: report.utility.name,
      dmaName: report.dma.name,
      branchName: report.branch?.name || null,
      teamName: report.team?.name || null,
      assignedEngineerName: report.assignedEngineer?.name || null,
    }

    return NextResponse.json(formattedReport, { status: 201 })
  } catch (error) {
    console.error('Error creating report:', error)
    return NextResponse.json({ error: 'Failed to create report' }, { status: 500 })
  }
}